import 'package:flutter_bloc/flutter_bloc.dart'; import '../../device_management/model/device_model_local.dart'; class DashboardSearchCubit extends Cubit<List<DeviceModelLocal>> { DashboardSearchCubit() : super([]); void search(List<DeviceModelLocal> all, String query) { if (query.isEmpty) { emit(all); return; } emit(all.where((d) => d.deviceName.toLowerCase().contains(query.toLowerCase())).toList()); } void reset(List<DeviceModelLocal> all) => emit(all); }